IACE,kBAAA;Ef4wCF;Ee1wCA;IACE,kBAAA;IACA,mBAAA;Ef4wCF;EezwCA,2BAAA;EACA;IACE,mBAAA;Ef2wCF;EexwCA,mBAAA;EACA;IACE,cAAA;Ef0wCF;EexwCA;IACE,gBAAA;Ef0wCF;EexwCA;IACE,sBAAA;Ef0wCF;EevwCA;IACE,aAAA;IACA,kBAAA;EfywCF;EevwCA;IACE,YAAA;EfywCF;EetwCA,8CAAA;EACA;IACE,aAAA;IACA,cAAA;EfwwCF;AACF;AerwCA,4BAAA;AlBtOE;EkB4OA,8BAAA;EACA;IACE,eAAA;EfmwCF;AACF;AehwCA,mCAAA;AlB7OE;EkBmPA;IACE,eAAA;Ef8vCF;AACF","file":"style.css","sourcesContent":["/*=== MEDIA QUERY ===*/\n@mixin mobile-xs{\n  @media(max-width:400px){\n    @content;\n  }\n}\n@mixin mobile{\n  @media(max-width:480px){\n    @content;\n  }\n}\n@mixin tablet{\n  @media(max-width:768px){\n    @content;\n  }\n}\n@mixin desktop{\n  @media(max-width:992px){\n    @content;\n  }\n}\n@mixin large-desktop{\n  @media(max-width:1200px){\n    @content;\n  }\n}","// Fonts \n@import url('https://fonts.googleapis.com/css?family=Barlow+Condensed:400,500,600,700|Montserrat|Poppins:400,500,600,700');\n\n\nbody {\n  line-height: 1.8;\n  font-family: $secondary-font;\n  -webkit-font-smoothing: antialiased;\n  font-size: 16px;\n  color: rgba(0,0,0,0.6);\n  \n\n}\nh1,.h1,h2,.h2,h3,.h3,h4,.h4,h5,.h5,h6,.h6 {\n  font-family: $primary-font; \n  font-weight:700;\n  color: $black;\n  letter-spacing: .5px;\n}\n\nh1,.h1 {\n  font-size:48px;\n   text-transform: uppercase;\n}\nh2,.h2{\n  font-size: 38px;\n   text-transform: uppercase;\n}\nh3,.h3{\n  font-size: 28px;\n  line-height: 38px;\n  text-transform: uppercase;\n}\nh4 ,.h4{\n  font-size:22px;\n  line-height: 30px;\n}\n\nh5,.h5 {\n  font-size:18px;\n  line-height: 24px;\n}\nh6,.h6 {\n  font-size:16px;\n text-transform: uppercase;\n font-weight: 400;\n}\n\n.font-primary{\n  font-family: $primary-font;\n}\n\n.font-secondary{\n  font-family: $secondary-font;\n}\n\n","$light: #fff;\n$primary-color: #d82a2a;\n$secondary-color: #f9f9f9;\n$extra-color: #181a23;\n$black: #232323;\n$black-light: #272727;\n$border-color:#dedede;\n$primary-font:'Barlow Condensed', sans-serif;\n$secondary-font:'Montserrat', sans-serif;\n","/*=== MEDIA QUERY ===*/\n@import url(\"https://fonts.googleapis.com/css?family=Barlow+Condensed:400,500,600,700|Montserrat|Poppins:400,500,600,700\");\nbody {\n  line-height: 1.8;\n  font-family: \"Montserrat\", sans-serif;\n  -webkit-font-smoothing: antialiased;\n  font-size: 16px;\n  color: rgba(0, 0, 0, 0.6);\n}\n\nh1, .h1, h2, .h2, h3, .h3, h4, .h4, h5, .h5, h6, .h6 {\n  font-family: \"Barlow Condensed\", sans-serif;\n  font-weight: 700;\n  color: #232323;\n  letter-spacing: 0.5px;\n}\n\nh1, .h1 {\n  font-size: 48px;\n  text-transform: uppercase;\n}\n\nh2, .h2 {\n  font-size: 38px;\n  text-transform: uppercase;\n}\n\nh3, .h3 {\n  font-size: 28px;\n  line-height: 38px;\n  text-transform: uppercase;\n}\n\nh4, .h4 {\n  font-size: 22px;\n  line-height: 30px;\n}\n\nh5, .h5 {\n  font-size: 18px;\n  line-height: 24px;\n}\n\nh6, .h6 {\n  font-size: 16px;\n  text-transform: uppercase;\n  font-weight: 400;\n}\n\n.font-primary {\n  font-family: \"Barlow Condensed\", sans-serif;\n}\n\n.font-secondary {\n  font-family: \"Montserrat\", sans-serif;\n}\n\nhtml, body {\n  overflow-x: hidden;\n  width: 100%;\n  word-wrap: break-word;\n  -webkit-box-sizing: border-box;\n  -moz-box-sizing: border-box;\n  box-sizing: border-box;\n}\n\n* {\n  -webkit-box-sizing: border-box;\n  -moz-box-sizing: border-box;\n  box-sizing: border-box;\n}\n\n.navbar-toggle .icon-bar {\n  background: #d82a2a;\n}\n\ninput[type=email], input[type=password], input[type=text], input[type=tel] {\n  box-shadow: none;\n  height: 50px;\n  outline: none;\n  font-size: 14px;\n}\ninput[type=email]:focus, input[type=password]:focus, input[type=text]:focus, input[type=tel]:focus {\n  box-shadow: none;\n  border: 1px solid #d82a2a;\n}\n\n.form-control {\n  box-shadow: none;\n  border-radius: 0;\n}\n.form-control:focus {\n  box-shadow: none;\n  border: 1px solid #d82a2a;\n}\n\n.btn {\n  display: inline-block;\n  font-size: 14px;\n  letter-spacing: 1px;\n  padding: 18px 35px;\n  text-transform: uppercase;\n  border-radius: 0;\n  font-weight: 700;\n  -webkit-transition: all 0.5s ease;\n  -moz-transition: all 0.5s ease;\n  -ms-transition: all 0.5s ease;\n  -o-transition: all 0.5s ease;\n  transition: all 0.5s ease;\n  border: 1px solid transparent;\n}\n\n.btn-main, .btn-small, .btn-transparent {\n  background: linear-gradient(90deg, #a31919 0%, #b74c4c 100%);\n  color: #fff;\n}\n.btn-main:hover, .btn-small:hover, .btn-transparent:hover {\n  background: linear-gradient(90deg, #b74c4c 0%, #a31919 100%);\n  color: #fff !important;\n  -webkit-transform: translateY(-5px);\n  -moz-transform: translateY(-5px);\n  -ms-transform: translateY(-5px);\n  -o-transform: translateY(-5px);\n  transform: translateY(-5px);\n}\n\n.btn-solid-border {\n  border: 2px solid #d82a2a;\n  background: transparent;\n  color: #fff;\n}\n.btn-solid-border:hover {\n  border: 2px solid #d82a2a;\n  background: #d82a2a;\n}\n\n.btn-white {\n  border: 2px solid #fff;\n  background: #fff;\n  color: #232323;\n}\n.btn-white:hover {\n  border: 1px solid #d82a2a;\n  background: #d82a2a;\n  color: #fff !important;\n}\n\n.btn-transparent {\n  background: transparent;\n  padding: 0;\n  color: #d82a2a;\n}\n.btn-transparent:hover {\n  background: transparent;\n  color: #d82a2a;\n}\n\n.btn-large {\n  padding: 20px 45px;\n}\n.btn-large.btn-icon i {\n  font-size: 16px;\n  vertical-align: middle;\n  margin-right: 5px;\n}\n\n.btn-small {\n  padding: 10px 25px;\n  font-size: 12px;\n}\n\n.btn-round {\n  border-radius: 4px;\n}\n\n.btn-round-full {\n  border-radius: 50px;\n}\n\n.btn.active:focus, .btn:active:focus, .btn:focus {\n  outline: 0;\n}\n\n.bg-shadow {\n  background-color: #fff;\n  box-shadow: 0 16px 24px rgba(0, 0, 0, 0.08);\n  padding: 20px;\n}\n\n.bg-gray {\n  background: #f0f2f4;\n}\n\n.bg-primary {\n  background: #d82a2a !important;\n}\n\n.section {\n  padding: 100px 0;\n}\n\n.section-title {\n  margin-bottom: 70px;\n}\n.section-title .title {\n  font-size: 50px;\n  line-height: 50px;\n}\n.section-title p {\n  color: #666;\n  font-family: \"Montserrat\", sans-serif;\n}\n\n.page-title {\n  padding: 155px 0 100px;\n}\n\n.overly, .bg-4 {\n  position: relative;\n}\n.overly:before, .bg-4:before {\n  content: \"\";\n  position: absolute;\n  left: 0;\n  top: 0;\n  bottom: 0;\n  right: 0;\n  width: 100%;\n  height: 100%;\n  background: #232323;\n  opacity: 0.8;\n}\n\n.overly-2, .textimonial, .cta, .slider, .page-title {\n  position: relative;\n}\n.overly-2:before, .textimonial:before, .cta:before, .slider:before, .page-title:before {\n  content: \"\";\n  position: absolute;\n  left: 0;\n  top: 0;\n  bottom: 0;\n  right: 0;\n  width: 100%;\n  height: 100%;\n  background: #000;\n  opacity: 0.6;\n}\n\n#success, #error {\n  display: none;\n}\n\n.text-color {\n  color: #d82a2a;\n}\n\n.text-black {\n  color: #232323;\n}\n\n.text-sm {\n  font-size: 14px;\n}\n\n.text-md {\n  font-size: 26px;\n  line-height: 36px;\n}\n\n.text-lg {\n  font-size: 56px;\n  line-height: 66px;\n}\n\n.no-spacing {\n  letter-spacing: 0px;\n}\n\na {\n  -webkit-transition: all 0.35s ease;\n  -moz-transition: all 0.35s ease;\n  -ms-transition: all 0.35s ease;\n  -o-transition: all 0.35s ease;\n  transition: all 0.35s ease;\n}\n\na:hover, a:focus {\n  color: #d82a2a !important;\n  text-decoration: none !important;\n  outline: 0;\n}\n\n.font-size-13 {\n  font-size: 13px;\n}\n\n.letter-spacing {\n  letter-spacing: 1px;\n}\n\n.bg-black-50 {\n  background: #181a23;\n}\n\n/* Responsive image handling */\nimg {\n  max-width: 100%;\n  height: auto;\n  display: block;\n}\n\nimg.img-fluid {\n  max-width: 100%;\n  width: 100%;\n  height: auto;\n}\n\n/* Container & row responsive */\n.container, .container-fluid {\n  width: 100%;\n  padding-left: 15px;\n  padding-right: 15px;\n  margin-left: auto;\n  margin-right: auto;\n  -webkit-box-sizing: border-box;\n  -moz-box-sizing: border-box;\n  box-sizing: border-box;\n}\n\n.row {\n  margin-left: -15px;\n  margin-right: -15px;\n  -webkit-box-sizing: border-box;\n  -moz-box-sizing: border-box;\n  box-sizing: border-box;\n}\n\n[class*=col-] {\n  padding-left: 15px;\n  padding-right: 15px;\n  -webkit-box-sizing: border-box;\n  -moz-box-sizing: border-box;\n  box-sizing: border-box;\n}\n\n/* Text overflow prevention */\nh1, h2, h3, h4, h5, h6 {\n  word-wrap: break-word;\n  overflow-wrap: break-word;\n  -webkit-hyphens: auto;\n  -moz-hyphens: auto;\n  hyphens: auto;\n}\n\np, span, a, li {\n  word-wrap: break-word;\n  overflow-wrap: break-word;\n}\n\n/* Card responsive */\n.card {\n  width: 100%;\n  -webkit-box-sizing: border-box;\n  -moz-box-sizing: border-box;\n  box-sizing: border-box;\n}\n\n/* Mobile-first responsive utilities */\n@media (max-width: 992px) {\n  .ml-lg-4 {\n    margin-left: 0 !important;\n  }\n  .mt-lg-0 {\n    margin-top: 0 !important;\n  }\n  .ml-auto {\n    margin-left: auto;\n  }\n}\n.navbar-nav li {\n  padding: 0px 10px;\n}\n.navbar-nav .nav-link {\n  font-family: \"Montserrat\", sans-serif;\n  color: #fff;\n  text-transform: uppercase;\n  font-size: 17px;\n  letter-spacing: 1px;\n  -webkit-transition: all 0.25s ease;\n  -moz-transition: all 0.25s ease;\n  -ms-transition: all 0.25s ease;\n  -o-transition: all 0.25s ease;\n  transition: all 0.25s ease;\n}\n.navbar-nav .nav-link:hover, .navbar-nav .nav-link:focus {\n  color: #d82a2a;\n}\n\n.top-header {\n  border-bottom: 1px solid rgba(0, 0, 0, 0.05);\n  font-size: 14px;\n}\n.top-header ul li {\n  padding: 0px 25px;\n  border-left: 1px solid #dedede;\n}\n\n.dropdown {\n  height: 100%;\n}\n\n.dropdown-menu {\n  background: #1c1c1c;\n  border-radius: 0px;\n  box-shadow: 0 5px 5px 0 rgba(0, 0, 0, 0.03);\n  padding: 24px 0 26px;\n  min-width: 280px;\n  left: 0px;\n  top: 100%;\n  -webkit-transform: translateY(10%);\n  -moz-transform: translateY(10%);\n  -ms-transform: translateY(10%);\n  -o-transform: translateY(10%);\n  transform: translateY(10%);\n  visibility: hidden;\n  opacity: 0;\n  z-index: 10;\n  transition: all 0.3s ease 0s;\n  display: block;\n}\n\n.dropdown-item {\n  color: #c8c8c8;\n  text-transform: uppercase;\n  letter-spacing: 1px;\n  font-size: 12px;\n  padding: 0.55rem 2rem;\n}\n\n.dropdown-toggle::after {\n  display: none;\n}\n\n.dropdown:hover .dropdown-menu {\n  visibility: visible;\n  opacity: 1;\n  z-index: 20;\n  -webkit-transform: translateY(0%);\n  -moz-transform: translateY(0%);\n  -ms-transform: translateY(0%);\n  -o-transform: translateY(0%);\n  transform: translateY(0%);\n}\n\n.dropdown-item:hover {\n  background: transparent;\n  color: #d82a2a;\n}\n\nul.dropdown-menu li {\n  padding-left: 0px !important;\n}\n\n.fixed-nav {\n  background: #181a23;\n}\n\n.navbar-toggler {\n  background-color: #fff;\n  border: 1px solid #fff;\n  border-radius: 0px;\n  padding: 5px 10px;\n}\n\n.navbar-collapse.collapse.show {\n  background: #181a23;\n}\n\n/* Responsive Navbar */\n@media (max-width: 992px) {\n  .navbar-nav li {\n    padding: 0px;\n  }\n  .nav-link {\n    font-size: 14px;\n    padding: 12px 0;\n  }\n  .dropdown-menu {\n    min-width: auto;\n    background: #232323;\n  }\n}\n@media (max-width: 768px) {\n  .navbar-nav li {\n    padding: 8px 0;\n  }\n  .nav-link {\n    font-size: 13px;\n    letter-spacing: 0.5px;\n    padding: 10px 0;\n  }\n  .dropdown-menu {\n    padding: 15px 0 20px;\n    min-width: 100%;\n  }\n  .dropdown-item {\n    padding: 0.4rem 1rem;\n    font-size: 11px;\n  }\n}\n@media (max-width: 480px) {\n  .navbar-nav li {\n    padding: 5px 0;\n  }\n  .nav-link {\n    font-size: 12px;\n    letter-spacing: 0px;\n    padding: 8px 0;\n  }\n}\n.slider {\n  background: url(\"../images/bg/bg-71.jpg\") no-repeat 0% 0%;\n  background-size: cover;\n  padding: 180px 0px;\n}\n.slider h1 {\n  font-size: 85px;\n  line-height: 110px;\n}\n.slider span.subhead {\n  color: #fff;\n  letter-spacing: 5px;\n  border: 2px solid #fff;\n  padding: 3px 15px 5px 15px;\n  opacity: 0.8;\n}\n\n/* Responsive Slider */\n@media (max-width: 992px) {\n  .slider {\n    padding: 120px 0px;\n  }\n  .slider h1 {\n    font-size: 56px;\n    line-he